const mongoose = require('mongoose');

async function queryBuilder(filterObject, projectionSpecs, sortCriteria) {
    const modelName = "YourModel"; // Replace with your actual Model Name
    if (!mongoose.models[modelName]) {
        return `Model ${modelName} not found`;
    }
    
    let query = mongoose.models[modelName].find();
    
    if (filterObject) {
        query = query.where(filterObject);
    }
  
    if (projectionSpecs) {
        query = query.select(projectionSpecs);
    }
  
    if (sortCriteria) {
        query = query.sort(sortCriteria);
    }
  
    try {
        const results = await query.exec(); // Execute the Query
        return results;
    } catch(err) {
        console.log('Error executing query:', err);
    }
}